bool HoleDrilling::Avoid_repetition_hole(std::vector<Face*> SelectedHoleInWallFaceList0, tag_t InWallFaceTag)
{
	bool RepetitionFlag;
	for (std::vector<Face*>::size_type j = 0; j != SelectedHoleInWallFaceList0.size(); j++)
	{
		Face *SelectFace = SelectedHoleInWallFaceList0[j];
		tag_t SelectFaceTag = SelectFace->Tag();
		if (SelectFaceTag == InWallFaceTag)
		{
			RepetitionFlag = TRUE;
			break;
		}
		else
		{
			RepetitionFlag = FALSE;
		}
	}
	return RepetitionFlag;

}
